    public function fetch_markets($params = array ()): array {
        /**
         * retrieves $data on all $markets for zebpayfutures
         *
         * @see https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/public-endpoints.md#get-trading-pairs
         *
         * @param {array} [$params] extra parameters specific to the exchange api endpoint
         * @return {array[]} an array of objects representing $market $data
         */
        $response = $this->publicGetExTradepairs ($params);
        //
        //    {
        //        "data" => {
        //            "symbol" => "ETH-INR",
        //            "name" => "ETH-INR",
        //            "baseCurrency" => "ETH",
        //            "quoteCurrency" => "INR",
        //            "feeCurrency" => "INR",
        //            "baseMinSize" => "",
        //            "quoteMinSize" => "100",
        //            "baseMaxSize" => "",
        //            "quoteMaxSize" => "2000",
        //            "baseIncrement" => "0.00001"
        //            "quoteIncrement" => "0.00001",
        //            "enableTrading" => true
        //        }
        //    }
        //
        $result = array();
        $data = $this->safe_value($response, 'data', array());
        $markets = $this->safe_value($data, 'tradePairs', array());
        for ($i = 0; $i < count($markets); $i++) {
            $market = $markets[$i];
            $id = $this->safe_string($market, 'symbol');
            $baseId = $this->safe_string($market, 'baseCurrency');
            $quoteId = $this->safe_string($market, 'quoteCurrency');
            $base = $this->safe_currency_code($baseId);
            $quote = $this->safe_currency_code($quoteId);
            $result[] = array(
                'id' => $id,
                'symbol' => $market->symbol,
                'base' => $base,
                'quote' => $quote,
                'baseId' => $baseId,
                'quoteId' => $quoteId,
                'spot' => true,
                'margin' => false,
                'future' => false,
                'option' => false,
                'active' => null,
                'contract' => null,
                'taker' => null,
                'maker' => null,
                'strike' => null,
                'optionType' => null,
                'precision' => null,
                'limits' => array(
                    'size' => array(
                        'min' => $this->safe_string($market, 'baseMinSize'),
                        'max' => $this->safe_string($market, 'baseMaxSize'),
                    ),
                ),
                'info' => $market,
            );
        }
        return $result;
    }

