                        'max' => null,
                    ),
                    'deposit' => array(
                        'min' => $this->parse_number($minDepositString),
                        'max' => null,
                    ),
                ),
                'networks' => $networks,
            );
        }
        return $result;
    }

    public function create_order(string $symbol, string $type, string $side, float $amount, ?float $price = null, $params = array ()) {
        /**
         *
         * @see https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#place-new-order
         *
         * create a trade order
         * @param {string} $symbol unified $symbol of the $market to create an order in
         * @param {string} $type must be 'limit'
         * @param {string} $side 'buy' or 'sell'
         * @param {float} $amount how much of currency you want to trade in units of base currency
         * @param {float} [$price] the $price at which the order is to be fulfilled, in units of the quote currency, ignored in $market orders
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array} an ~@link https://docs.ccxt.com/#/?id=order-structure order structure~
         */
        $this->load_markets();
        $market = $this->market($symbol);
        $request = array(
            'symbol' => $market['id'],
            'side' => strtoupper($side),
        );
        list($request, $params) = $this->order_request($symbol, $type, $amount, $request, $price, $params);
        $response = $this->privatePostExOrders ($this->extend($request, $params));
        if ($response->data === null) {
            throw new ExchangeError(json_encode ($response));
        }
        $orderId = $this->safe_value($response->data, 'orderId');
        return $this->safe_order(array(
            'info' => $response,
            'id' => (string) $orderId,
        ), $market);
    }

    public function fetch_trading_fee(string $symbol, $params = array ()): array {
        /**
         * the latest known information on the availability of the exchange API
         *
         * @see https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#get-exchange-fee
         *
         * @param {string} $symbol unified $symbol of the $market to fetch the order book for
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {array} [$params->side] $side to fetch trading fee
         * @return {array} a ~@link https://docs.ccxt.com/#/?id=exchange-status-structure status structure~
         */
        if ($symbol === null) {
            throw new ArgumentsRequired($this->id . ' fetchTradingFee() requires a $symbol argument');
        }
        $this->load_markets();
        $market = $this->market($symbol);
        $side = $this->safe_string($params, 'side', null);
        $request = array(
            'symbol' => $market['id'],
        );
        if ($side !== null) {
            $request['side'] = $side;
        }
        $response = $this->privateGetExFeeSymbol ($this->extend($request, $params));
        if ($response->data === null) {
            throw new ExchangeError(json_encode ($response));
        }
        //
        // {
        //     "statusDescription" => "Success",
        //     "data":
        //       {
        //         "symbol" => "BTCINR",
        //         "takerFeeRate" => "0.01",
        //         "makerFeeRate" => "0.05",
        //         "percentage" => true
        //       } ,
        //     "statusCode" => 200,
        // }
        //
        $data = $this->safe_value($response, 'data', array());
        $first = $this->safe_dict($data, 0);
        return array(
            'info' => $response,
            'symbol' => $symbol,
            'maker' => $this->safe_number($first, 'makerFeeRate'),
            'taker' => $this->safe_number($first, 'takerFeeRate'),
            'percentage' => $this->safe_bool($first, 'percentage'),
            'tierBased' => null,
        );
    }

