    public function cancel_order(string $id, ?string $symbol = null, $params = array ()) {
        /**
         * cancels an open order
         *
         * @see https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#cancel-order
         * @see https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#cancel-all-orders-for-a-$symbol
         *
         * @param {string} $id order $id
         * @param {string} $symbol unified $symbol of the market the order was made in
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {array} [$params->timestamp] Timestamp
         * @return {array} An ~@link https://docs.ccxt.com/#/?$id=order-structure order structure~
         */
        $this->load_markets();
        $timestamp = $this->safe_integer($params, 'timestamp');
        $params = $this->omit($params, array( 'timestamp' ));
        $request = array(
            'timestamp' => $timestamp,
        );
        $response = null;
        if ($id === null) {
            $request['symbol'] = $symbol;
            $response = $this->privateDeleteExOrders ($this->extend($request, $params));
        } else {
            $request['orderId'] = $id;
            $response = $this->privateDeleteExOrdersOrderId ($this->extend($request, $params));
        }
        if ($response->data === null) {
            throw new ExchangeError(json_encode ($response));
        }
        //
        //    {
        //        "data" => array(
        //            "orderId" => "12345",
        //            "symbol" => 'BTC-INR
        //        ),
        //    }
        //
        return $response;
    }

