    public function fetch_ohlcv(string $symbol, $timeframe = '1m', ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetches historical candlestick data containing the open, high, low, and close price, and the volume of a $market
         *
         * @see https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/public-endpoints.md#get-klinescandlesticks
         *
         * @param {string} $symbol unified $symbol of the $market to fetch OHLCV data for
         * @param {string} $timeframe the length of time each candle represents
         * @param {int} [$since] timestamp in ms of the earliest candle to fetch
         * @param {int} [$limit] the maximum amount of candles to fetch
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {int} [$params->endtime] the latest time in ms to fetch orders for
         * @return {int[][]} A list of candles ordered, open, high, low, close, volume
         */
        if ($symbol === null) {
            throw new ArgumentsRequired($this->id . ' fetchOHLCV() requires a $symbol argument');
        }
        $endtime = $this->safe_string($params, 'endTime');
        $starttime = $this->safe_string($params, 'startTime');
        $params = $this->omit($params, array( 'endtime' ));
        $this->load_markets();
        $market = $this->market($symbol);
        $request = array(
            'symbol' => $market['id'],
        );
        if ($limit === null) {
            $limit = 200; // default is 200
        }
        $request['startTime'] = $starttime;
        $request['limit'] = $limit; // max 200, default 200
        $request['endTime'] = $endtime;
        $request['interval'] = $timeframe;
        $response = null;
        if ($market['spot']) {
            $request['category'] = 'spot';
            $response = $this->publicGetMarketKlines ($this->extend($request, $params));
        }
        //
        //             array(
        //                 array(
        //                     "1670608800000",
        //                     "17071",
        //                     "17073",
        //                     "17027",
        //                     "17055.5",
        //                     "268611",
        //                     "15.74462667"
        //                 ),
        //                 array(
        //                     "1670605200000",
        //                     "17071.5",
        //                     "17071.5",
        //                     "17061",
        //                     "17071",
        //                     "4177",
        //                     "0.24469757"
        //                 ),
        //                 array(
        //                     "1670601600000",
        //                     "17086.5",
        //                     "17088",
        //                     "16978",
        //                     "17071.5",
        //                     "6356",
        //                     "0.37288112"
        //                 )
        //             )
        //
        return $this->parse_ohlcvs($response, $market, $timeframe, $since, $limit);
    }

    public function fetch_order(?string $id, ?string $symbol = null, $params = array ()) {
        /**
         * fetches information on an order made by the user
         *
         * @see https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#get-order-details
         *
         * @param {string} $id order $id
         * @param {string} $symbol unified $symbol of the $market the order was made in
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {string} [$params->timestamp] cancel order by client order $id
         * @return {array} An ~@link https://docs.ccxt.com/#/?$id=order-structure order structure~
         */
        $this->load_markets();
        $request = array();
        $timestamp = $this->safe_integer($params, 'timestamp');
        if ($id === null) {
            throw new InvalidOrder($this->id . ' fetchOrder() requires parameter orderId in params');
        }
        $params = $this->omit($params, array( 'timestamp' ));
        $request['orderId'] = $id;
        $request['timestamp'] = $timestamp;
        $response = $this->privateGetExOrdersOrderId ($this->extend($request, $params));
        if ($response->data === null) {
            throw new ExchangeError(json_encode ($response));
        }
        //
        //     {
        //         "data" => {
        //                     "orderId" => "64507d02921f1c0001ff6892-123-zeb",
        //                     "datetime" => "2025-03-14T14:34:34.4567",
        //                     "timestamp" => 1741962557553,
        //                     "status" => "open",
        //                     "origQty" => "12",
        //                     "symbol" => "BTCINR",
        //                     "type" => "market",
        //                     "side" => "buy",
        //                     "price" => 700000,
        //                     "avgExecutedPrice" => 0,
        //                     "filledQty" => "0",
        //                     "openQty" => 0.002,
        //                     "feeCurrency" => "INR",
        //                     "fees" => "0",
        //                     "tds" => "0",
        //                     "tax" => "0"
        //                 }
        //     }
        //
        $market = ($symbol !== null) ? $this->market($symbol) : null;
        $responseData = $this->safe_dict($response, 'data');
        return $this->parse_order($responseData, $market);
    }

