    public function fetch_order_trades(string $id, ?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()) {
        /**
         * fetch all the $trades made from a single order
         *
         * @see https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#get-order-fills
         *
         * @param {string} $id order $id
         * @param {string} $symbol unified market $symbol
         * @param {int} [$since] the earliest time in ms to fetch $trades for
         * @param {int} [$limit] the maximum number of $trades to retrieve
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array[]} a list of ~@link https://docs.ccxt.com/#/?$id=trade-structure trade structures~
         */
        $this->load_markets();
        $timestamp = $this->safe_integer($params, 'timestamp');
        $request = array(
            'orderId' => $id,
            'timestamp' => $timestamp,
        );
        $params = $this->omit($params, array( 'timestamp' ));
        $response = $this->privateGetExOrdersFillsOrderId ($this->extend($request, $params));
        if ($response->data === null) {
            throw new ExchangeError(json_encode ($response));
        }
        //
        //         {
        //             "orderId" => "456789",
        //             "symbol" => "LINK_USDT",
        //             "origQty" => "1.5",
        //             "orderId" => "30249408733945856",
        //             "side" => "BUY",
        //             "type" => "LIMIT",
        //             "matchRole" => "MAKER",
        //             "createTime" => 1648200366864,
        //             "price" => "3.1",
        //             "avgExecutedPrice" => "2.3456"
        //             "openQty" => "1",
