    public function order_request($symbol, $type, $amount, $request, $price = null, $params = array ()) {
        $upperCaseType = strtoupper($type);
        $triggerPrice = $this->safe_string($params, 'stopPrice');
        $timestamp = $this->safe_integer($params, 'timestamp');
        $quoteOrderQty = $this->safe_string($params, 'quoteOrderQty');
        $params = $this->omit($params, array( 'stopPrice', 'timestamp', 'quoteOrderQty' ));
        $request['type'] = $upperCaseType;
        if ($upperCaseType === 'MARKET') {
            if ($quoteOrderQty === null) {
                throw new ExchangeError($this->id . ' market createOrder() requires quoteOrderQty');
            }
            $request['quoteOrderQty'] = $quoteOrderQty;
        } else {
            $request['stopPrice'] = $triggerPrice;
            $request['quantity'] = 'strval' ($amount);
            $request['price'] = 'strval' ($price);
        }
        $request['timestamp'] = $timestamp;
        return array( $request, $params );
    }

    public function parse_balance($response): array {
        $result = array(
            'info' => $response,
            'timestamp' => null,
            'datetime' => null,
        );
        $currencyList = $this->safe_list($response, 'data');
        for ($i = 0; $i < count($currencyList); $i++) {
            $entry = $currencyList[$i];
            $account = $this->account();
            $account['total'] = $this->safe_string($entry, 'balance');
            $account['free'] = $this->safe_string($entry, 'available');
            $account['used'] = $this->safe_string($entry, 'locked');
            $currencyId = $this->safe_string($entry, 'currency');
            $code = $this->safe_currency_code($currencyId);
            $result[$code] = $account;
        }
        return $this->safe_balance($result);
    }

    public function sign($path, $api = 'public', $method = 'GET', $params = array (), $headers = null, $body = null) {
        $url = $this->urls['api'][$api];
        $versions = $this->safe_value($this->options, 'versions', array());
        $apiVersions = $this->safe_value($versions, $api, array());
        $methodVersions = $this->safe_value($apiVersions, $method, array());
        $defaultVersion = $this->safe_string($methodVersions, $path, $this->version);
        $version = $this->safe_string($params, 'version', $defaultVersion);
        $tail = '/api/' . $version . '/' . $this->implode_params($path, $params);
        $url .= $tail;
        // $timestamp = (string) $this->milliseconds();
        $signature = '';
        $query = $this->omit($params, $this->extract_params($path));
        $queryLength = $query;
        if ($api === 'public') {
            if ($queryLength) {
                $url .= '?' . $this->urlencode($query);
            }
        } else {
            $this->check_required_credentials();
            if ($method === 'GET' || $method === 'DELETE') {
                // For GET/DELETE => Append $params to URL and sign the $query string
                // $params['timestamp'] = $timestamp;
                if ($method === 'DELETE' && $path->includes ('ex/orders')) {
                    $params = $this->omit($params, 'orderId');
                }
                if ($method === 'GET' && $path->includes ('ex/orders/')) {
                    $params = $this->omit($params, 'orderId');
                }
                $queryString = $this->urlencode($params);
                $signature = $this->hmac($queryString, $this->secret, 'sha256', 'hex');
                $url .= '?' . $queryString;
            } else {
                // For POST/PUT => Convert $body to JSON and sign the stringified payload
                // $params['timestamp'] = $timestamp;
                $body = json_encode ($params);
                $signature = $this->hmac($body, $this->secret, 'sha256', 'hex');
            }
            $headers = array(
                'X-AUTH-APIKEY' => $this->apiKey,
                'X-AUTH-SIGNATURE' => $signature,
            );
            $headers['Content-Type'] = 'application/json';
        }
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }

    public function handle_errors(int $code, string $reason, string $url, string $method, array $headers, string $body, $response, $requestHeaders, $requestBody) {
        if (!$response) {
            $this->throw_broadly_matched_exception($this->exceptions['broad'], $body, $body);
            return null;
        }
        //
        // bad
        //     array( "code" => "400100", "msg" => "validation.createOrder.clientOidIsRequired" )
        // good
        //     array( $code => "200000", data => array( ... ))
        //
        $errorCode = $this->safe_string($response, 'code');
        $message = $this->safe_string($response, 'msg', '');
        $feedback = $this->id . ' ' . $message;
        $this->throw_exactly_matched_exception($this->exceptions['exact'], $message, $feedback);
        $this->throw_exactly_matched_exception($this->exceptions['exact'], $errorCode, $feedback);
        $this->throw_broadly_matched_exception($this->exceptions['broad'], $body, $feedback);
        return null;
    }
